@implementation WBMineFunctionView

- (instancetype)init {
    self = [super initWithFrame:CGRectZero];
    if (self) {
        self.hasNewPromoToReceive = false;
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(updateItemBadge) name:WBUserMsgStatusUpdateNotification object:nil];
