#pragma mark - 功能数据

- (void)setupData {
    NSArray *itemConfigs = @[
        @{@"code": @"settting", @"icon": @"HomePage_setting", @"title": @"设置"},
        @{@"code": @"promo", @"icon": @"HomePage_promo", @"title": @"优惠券"},
        @{@"code": @"feedback", @"icon": @"HomePage_feedback", @"title": @"客服反馈"},
        @{@"code": @"about", @"icon": @"HomePage_about", @"title": @"关于"},
        @{@"code": @"update", @"icon": @"HomePage_update", @"title": @"检查更新"},
        @{@"code": @"share", @"icon": @"HomePage_share", @"title": @"分享朋友"}
    ];

    _functionItems = [NSMutableArray array];
    for (NSDictionary *config in itemConfigs) {
        WBMineFunctionItem *item = [[WBMineFunctionItem alloc] initWithCode:config[@"code"] icon:config[@"icon"] title:config[@"title"]];
        [_functionItems addObject:item];
    }
}

// 更新单个功能的动态数据
- (void)updateDynamicDataForFunctionType:(NSString *)functionType showNotice:(BOOL)showNotice tipString:(NSString *)tipString {
    // 使用谓词查找对应的item
    NSPredicate *predicate = [NSPredicate predicateWithFormat:@"code == %@", functionType];
    NSArray *filteredItems = [self.functionItems filteredArrayUsingPredicate:predicate];

    if (filteredItems.count > 0) {
        WBMineFunctionItem *targetItem = filteredItems.firstObject;
        targetItem.showNotice = showNotice;
        targetItem.tipString = tipString ?: @"";

        // 找到该item在数组中的位置来刷新对应的Cell
        NSUInteger index = [self.functionItems indexOfObject:targetItem];
        if (index != NSNotFound) {
            NSIndexPath *indexPath = [NSIndexPath indexPathForItem:index inSection:0];
            [self.collectionView reloadItemsAtIndexPaths:@[indexPath]];
        }
    }
}


#pragma mark - events

- (void)updateUI {
    NSDictionary *config = [self vipStatusConfig];
    _titleImageView.image = [UIImage imageNamed:config[@"titleImageName"]];
    [self.collectionView reloadData];
}

- (void)updateItemBadge {
    __block NSString *tipString = @"待使用";  // 默认值
    [[WBNetworkManager defaultManager] requestAllMyPromoCodeWithCallback:^(NSArray<WBPromoModel *> * _Nullable promoModels, NSError * _Nullable error) {
        if (!error && promoModels.count > 0) {
            NSMutableArray *validPromos = [NSMutableArray array];
            for (WBPromoModel *promo in promoModels) {
                if (!promo.expired && !promo.useDate) {
                    [validPromos addObject:promo];
                };
            }
            if (validPromos && validPromos.count > 0) {
                WBSettingManager.sharedManager.HasNewPromo = TRUE;
                for (WBPromoModel *promo in validPromos) {
                    if (promo.unclaimed) {
                        tipString = @"待领取";
                        break;
                    }
                }
            }
            if (WBSettingManager.sharedManager.HasNewPromo) {
                [self updateDynamicDataForFunctionType:@"promo" showNotice:YES tipString:tipString];
            } else {
                [self updateDynamicDataForFunctionType:@"promo" showNotice:NO tipString:@""];
            }
        }
    }];

    if (WBSettingManager.sharedManager.HasNewMessage) {
        [self updateDynamicDataForFunctionType:@"feedback" showNotice:YES tipString:@"新消息"];
    } else {
        [self updateDynamicDataForFunctionType:@"feedback" showNotice:NO tipString:@""];
    }

    if (WBSettingManager.sharedManager.HasUpdate) {
        [self updateDynamicDataForFunctionType:@"update" showNotice:YES tipString:@""];
    } else {
        [self updateDynamicDataForFunctionType:@"update" showNotice:NO tipString:@""];
    }

    if (WBSettingManager.sharedManager.HasNewShare) {
        [self updateDynamicDataForFunctionType:@"share" showNotice:YES tipString:@"赢好礼"];
    } else {
        [self updateDynamicDataForFunctionType:@"share" showNotice:NO tipString:@""];
    }
}

#pragma mark - UICollectionViewDataSource

- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return self.functionItems.count;
}

- (__kindof UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    WBMineFunctionCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"WBMineFunctionCell" forIndexPath:indexPath];
    WBMineFunctionItem *item = self.functionItems[indexPath.item];

    [cell configureWithIcon:item.icon title:item.title showNotice:item.showNotice tipString:item.tipString];

    return cell;
}


