    NSString *vappBundleId = [WBAppManager sharedManager].vappBundleId;
    if (stashedAction) {
        if(vappBundleId) {
            [WBHomeViewController msgTappedCheckAndLaunchVApp:vappBundleId];
        }
        [WBAppManager sharedManager].stashedAction = nil;
        [stashedAction executeWithDefaultHandler:nil];
    }

}

