+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBSettingManager alloc] init];
    });
    return instance;
}

- (instancetype)init {
    self = [super init];
    self.userDefaults = [NSUserDefaults standardUserDefaults];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleShareLinkNotification:) name:WBPresentShareUrlNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleShareTitleNotification:) name:WBPresentShareContentNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(backToOriginalShareInfoNotification) name:WBBackToOriginalShareUrlNotification object:nil];
    return self;
}

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

- (void)handleShareLinkNotification:(NSNotification *)notification {
    // 从通知中获取 userInfo 字典
    NSDictionary *shareLinkInfo = [notification userInfo];
    NSString *shareLink = [shareLinkInfo objectForKey:@"shareUrl"];
    if(shareLink) {
        self.ShareURL = shareLink;
    } else {
        // 使用user/token里面的默认分享链接
    }
}

- (void)handleShareTitleNotification:(NSNotification *)notification {
    // 从通知中获取 userInfo 字典
    NSDictionary *shareContentInfo = [notification userInfo];
    NSString *shareTitle = [shareContentInfo objectForKey:@"shareTitle"];
    NSString *shareDescription = [shareContentInfo objectForKey:@"shareDescription"];
    if(shareTitle) {
        self.ShareTitle = shareTitle;
    } else {
        // 使用user/token里面的默认分享标题
    }
    if(shareDescription) {
        self.ShareDescription = shareDescription;
    } else {
        self.ShareDescription = @"";
    }
}

// 分享完当前打开的网页之后，重置为默认分享网页（分享落地页）
- (void)backToOriginalShareInfoNotification {
    self.ShareURL = self.originalShareUrl;
    self.ShareTitle = self.OriginalShareTitle;
    self.ShareDescription = self.OriginalShareDescription;
}

- (BOOL)EnableADS {
    return [self isAdsAppIdValid:self.ADSAppId];
}

- (BOOL)isAdsAppIdValid:(NSString *)adsAppId {
    return adsAppId.length && [adsAppId integerValue] != 0;
}

// 判断是否终身会员
- (BOOL)isLifetimeMemberWithExpireDate:(NSString *)expireDateString {
    if (!self.IsSVIP) {
        return NO;
    }
    // 创建临界日期
    static NSDate *criticalDate;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        NSDateComponents *comps = [[NSDateComponents alloc] init];
        comps.year = 2098;
        comps.month = 12;
        comps.day = 31;
        criticalDate = [[NSCalendar currentCalendar] dateFromComponents:comps];
    });

    // 转换传入的日期字符串
    static NSDateFormatter *formatter;
    static dispatch_once_t formatterToken;
    dispatch_once(&formatterToken, ^{
        formatter = [[NSDateFormatter alloc] init];
        formatter.dateFormat = @"yyyy-MM-dd";
    });
    NSDate *expireDate = [formatter dateFromString:expireDateString];

    if (!expireDate) {
        return NO;
    }
    return [expireDate compare:criticalDate] == NSOrderedDescending;
}

